cd /workspace/YatCC && cat > /tmp/debug_test.cpp << 'EOF'
#include "EmitIR.hpp"
#include "Json2Asg.hpp"
#include "asg.hpp"
#include <fstream>
#include <iostream>
#include <llvm/IR/Verifier.h>
#include <llvm/Support/MemoryBuffer.h>

int main(int argc, char* argv[]) {
  auto inFileOrErr = llvm::MemoryBuffer::getFile(argv[1]);
  auto inFile = std::move(inFileOrErr.get());
  std::error_code ec;
  llvm::StringRef outPath(argv[2]);
  llvm::raw_fd_ostream outFile(outPath, ec);

  std::cerr << "Parsing JSON..." << std::endl;
  auto json = llvm::json::parse(inFile->getBuffer());
  std::cerr << "JSON parsed OK" << std::endl;

  Obj::Mgr mgr;
  Json2Asg json2asg(mgr);
  std::cerr << "Building ASG..." << std::endl;
  auto asg = json2asg(json.get());
  std::cerr << "ASG built OK: " << asg << " decls=" << asg->decls.size() << std::endl;
  mgr.mRoot = asg;
  mgr.gc();

  std::cerr << "Emitting IR..." << std::endl;
  llvm::LLVMContext ctx;
  EmitIR emitIR(mgr, ctx);
  auto& mod = emitIR(asg);
  std::cerr << "IR emitted OK" << std::endl;
  mgr.gc();

  mod.print(outFile, nullptr, false, true);
  if (llvm::verifyModule(mod, &llvm::outs()))
    return 3;
  return 0;
}
EOF
